/**
 * Bells — inject Robinhood testnet (46630) addresses into the wagmi-generated
 * contract bindings in src/contracts/*.gen.ts.
 *
 * The bindings are normally regenerated by `wagmi generate`, whose etherscan
 * plugin cannot fetch ABIs for a Blockscout-only chain. Since the ABIs are
 * unchanged (we deploy unmodified Nouns contracts), we only extend the
 * per-chain address maps. Idempotent: existing 46630 entries are replaced.
 *
 * Run after a testnet deployment:
 *   node scripts/add-robinhood-addresses.mjs
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const CHAIN_ID = 46630;
const ZERO = '0x0000000000000000000000000000000000000000';

const deployed = JSON.parse(
  fs.readFileSync(
    path.join(__dirname, '../../nouns-contracts/bells/addresses.robinhood-testnet.json'),
    'utf8',
  ),
);

// gen file -> exported address const name -> deployed contract key
const TARGETS = {
  'nouns-auction-house.gen.ts': {
    nounsAuctionHouseAddress: deployed.NounsAuctionHouseProxy,
  },
  'nouns-token.gen.ts': { nounsTokenAddress: deployed.NounsToken },
  'nouns-governor.gen.ts': { nounsGovernorAddress: deployed.NounsDAOProxyV3 },
  'nouns-treasury.gen.ts': { nounsTreasuryAddress: deployed.NounsDAOExecutorProxy },
  // No legacy (V1) treasury on this chain; point at the only executor.
  'nouns-legacy-treasury.gen.ts': {
    nounsLegacyTreasuryAddress: deployed.NounsDAOExecutorProxy,
  },
  'nouns-data.gen.ts': { nounsDataAddress: deployed.NounsDAODataProxy },
  'nouns-descriptor.gen.ts': { nounsDescriptorAddress: deployed.NounsDescriptorV3 },
  'weth.gen.ts': { wethAddress: deployed.WETH },
  // Mainnet-only payment infra (USDC top-ups, streams, price oracle) has no
  // Bells equivalent. Zero-address entries keep the per-chain map types
  // consistent; the UI surfaces using them are pruned from the Bells nav.
  'nouns-token-buyer.gen.ts': { nounsTokenBuyerAddress: ZERO },
  'nouns-payer.gen.ts': { nounsPayerAddress: ZERO },
  'nouns-stream-factory.gen.ts': { nounsStreamFactoryAddress: ZERO },
  'meth.gen.ts': { mEthAddress: ZERO },
  'meth-staking.gen.ts': { mEthStakingAddress: ZERO },
  'steth.gen.ts': { stEthAddress: ZERO },
  'usdc.gen.ts': { usdcAddress: ZERO },
  'eth-to-usd-price-oracle.gen.ts': { ethToUsdPriceOracleAddress: ZERO },
};

const contractsDir = path.join(__dirname, '../src/contracts');

for (const [file, constants] of Object.entries(TARGETS)) {
  const filePath = path.join(contractsDir, file);
  let source = fs.readFileSync(filePath, 'utf8');

  for (const [constName, address] of Object.entries(constants)) {
    if (!address) throw new Error(`Missing deployed address for ${constName} (${file})`);

    // Drop any previous 46630 entries, then append ours to the map literal.
    // \r?\n handles CRLF checkouts on Windows. [ \t]* (not \s*) so the match
    // cannot start after a bare \r and swallow the previous line's \n.
    source = source.replaceAll(
      new RegExp(`^[ \\t]*${CHAIN_ID}: '0x[0-9a-fA-F]{40}',\\r?\\n`, 'gm'),
      '',
    );
    const mapRe = new RegExp(
      `(export const ${constName} = \\{\\r?\\n(?:.*\\r?\\n)*?)(\\} as const)`,
    );
    if (!mapRe.test(source)) throw new Error(`Could not find ${constName} map in ${file}`);
    source = source.replace(mapRe, `$1  ${CHAIN_ID}: '${address}',\n$2`);
  }

  fs.writeFileSync(filePath, source);
  console.log(`patched ${file}`);
}

console.log('Done — 46630 addresses injected.');
